/**
 * Impostor renderer contract:
 * - Unit instances are packed by BattleRuntime into fixed-stride float buffers.
 * - This renderer only interprets that buffer and performs layered billboard draws.
 * - Pitch-driven readability (front/top blend) is handled here, not in gameplay sim.
 * - Keep attribute layout synced with `UNIT_INSTANCE_STRIDE` and runtime writes.
 * - Any field reorder must update both shader attribute comments and runtime offsets.
 */
import {
  createProgram,
  createStaticQuadVao,
  createDynamicInstanceBuffer,
  updateDynamicBuffer
} from './WebGL2Context';
import { UNIT_INSTANCE_STRIDE } from '../snapshot/BattleSnapshotSchema';

export { UNIT_INSTANCE_STRIDE };

const VS = `#version 300 es
layout(location=0) in vec2 aQuadPos;
layout(location=1) in vec2 aUv;
layout(location=2) in vec4 iData0; // x y z size
layout(location=3) in vec4 iData1; // yaw team hp body
layout(location=4) in vec4 iData2; // gear vehicle silhouette tint
layout(location=5) in vec4 iData3; // selected flag ghost reserved
layout(location=6) in vec4 iData4; // bodyTop gearTop vehicleTop silhouetteTop

uniform mat4 uViewProj;
uniform vec3 uCameraRight;
uniform float uLayer;
uniform float uApplyYaw;
uniform float uTopBlend;

out vec2 vUv;
out float vTeam;
out float vHp;
out float vSliceFront;
out float vSliceTop;
out float vSelected;
out float vFlag;
out float vTint;
out float vGhost;

void main() {
  vec3 base = vec3(iData0.x, iData0.y, iData0.z);
  float size = max(1.0, iData0.w);
  vec3 rightV = normalize(vec3(uCameraRight.x, uCameraRight.y, 0.0));
  if (length(rightV) <= 0.0001) {
    rightV = vec3(1.0, 0.0, 0.0);
  }
  vec3 upV = vec3(0.0, 0.0, 1.0);
  vec3 rightT = rightV;
  vec3 upT = vec3(-rightV.y, rightV.x, 0.0);

  vec2 quad = aQuadPos;
  if (uApplyYaw > 0.5) {
    float c = cos(iData1.x);
    float s = sin(iData1.x);
    quad = vec2(
      (aQuadPos.x * c) - (aQuadPos.y * s),
      (aQuadPos.x * s) + (aQuadPos.y * c)
    );
  }

  vec3 worldV = base;
  worldV += rightV * (quad.x * size);
  worldV += upV * (quad.y * size * 1.92);

  vec3 worldT = base;
  worldT += rightT * (quad.x * size);
  worldT += upT * (quad.y * size * 1.02);
  worldT.z += size * 0.02;

  vec3 world = mix(worldV, worldT, clamp(uTopBlend, 0.0, 1.0));

  vUv = aUv;
  vTeam = iData1.y;
  vHp = iData1.z;
  vSelected = iData3.x;
  vFlag = iData3.y;
  vGhost = iData3.z;
  vTint = iData2.w;
  if (uLayer < 0.5) {
    vSliceFront = iData1.w;
    vSliceTop = iData4.x;
  } else if (uLayer < 1.5) {
    vSliceFront = iData2.x;
    vSliceTop = iData4.y;
  } else if (uLayer < 2.5) {
    vSliceFront = iData2.y;
    vSliceTop = iData4.z;
  } else {
    vSliceFront = iData2.z;
    vSliceTop = iData4.w;
  }

  gl_Position = uViewProj * vec4(world, 1.0);
}
`;

const FS = `#version 300 es
precision highp float;
precision highp sampler2DArray;

in vec2 vUv;
in float vTeam;
in float vHp;
in float vSliceFront;
in float vSliceTop;
in float vSelected;
in float vFlag;
in float vTint;
in float vGhost;

uniform vec3 uLightDir;
uniform float uPitchMix;
uniform float uTopBlend;
uniform sampler2DArray uTexArray;
uniform float uUseTexArray;
uniform float uLayer;
uniform float uTexLayerCount;

out vec4 outColor;

void main() {
  vec2 p = (vUv - vec2(0.5)) * vec2(1.0, 1.85);
  float rr = dot(p, p);
  if (rr > 0.95) discard;

  float z = sqrt(max(0.0, 1.0 - rr));
  vec3 normal = normalize(vec3(p.xy * 0.9, z));
  vec3 lightDir = normalize(uLightDir);
  float lambert = max(0.0, dot(normal, lightDir));
  float lit = 0.35 + (lambert * 0.75);

  vec3 teamTint = (vTeam < 0.5) ? vec3(0.55, 0.76, 1.0) : vec3(1.0, 0.58, 0.58);
  float pseudo = fract((vSliceFront + (uLayer * 7.0)) * 0.137);
  vec3 palette = vec3(
    0.36 + (0.42 * fract(pseudo * 2.3)),
    0.34 + (0.38 * fract(pseudo * 3.7)),
    0.30 + (0.36 * fract(pseudo * 5.1))
  );
  vec3 color = palette * mix(vec3(0.84), teamTint, 0.34 + 0.07 * uLayer);
  color *= max(0.35, min(2.0, vTint <= 0.001 ? 1.0 : vTint));
  if (uLayer > 2.5) {
    color = mix(color, teamTint, 0.55);
    color *= 0.72;
  }
  if (uUseTexArray > 0.5) {
    float frontLayer = floor(vSliceFront + 0.5);
    frontLayer = clamp(frontLayer, 0.0, max(0.0, uTexLayerCount - 1.0));
    vec4 frontTexel = texture(uTexArray, vec3(vUv, frontLayer));
    float topLayerRaw = floor(vSliceTop + 0.5);
    float topLayer = clamp(topLayerRaw, 0.0, max(0.0, uTexLayerCount - 1.0));
    vec4 topTexel = texture(uTexArray, vec3(vUv, topLayer));
    float topValid = step(0.0, vSliceTop);
    float topMix = clamp(uTopBlend, 0.0, 1.0) * topValid;
    vec3 texRgb = mix(frontTexel.rgb, topTexel.rgb, topMix);
    float texA = mix(frontTexel.a, topTexel.a, topMix);
    color = mix(color, texRgb, clamp(texA, 0.0, 1.0) * 0.72);
  }
  color = mix(color, color * 1.18, clamp(uPitchMix, 0.0, 1.0) * 0.18);
  color *= lit;
  color *= mix(0.5, 1.0, clamp(vHp, 0.0, 1.0));
  if (vGhost > 0.5) {
    color = mix(color, vec3(0.8, 0.9, 1.0), 0.3);
    color *= 0.82;
  }
  if (vSelected > 0.5) {
    color = mix(color, vec3(1.0, 0.95, 0.5), 0.22);
  }
  if (vFlag > 0.5) {
    color = mix(color, vec3(1.0, 1.0, 1.0), 0.12);
  }

  outColor = vec4(color, 1.0);
}
`;

const SHAPE_BODY = 0;
const SHAPE_GEAR = 1;
const SHAPE_VEHICLE = 2;
const clamp01 = (value) => Math.max(0, Math.min(1, Number(value) || 0));

const fillTextureLayer = (size, layerIndex, totalLayers, angleMode, shapeMode, normalMode = false) => {
  const data = new Uint8Array(size * size * 4);
  const hue = (layerIndex % Math.max(1, totalLayers)) / Math.max(1, totalLayers);
  const baseR = 80 + Math.floor(120 * Math.abs(Math.sin((hue * Math.PI * 2) + 0.2)));
  const baseG = 70 + Math.floor(120 * Math.abs(Math.sin((hue * Math.PI * 2) + 2.4)));
  const baseB = 70 + Math.floor(120 * Math.abs(Math.sin((hue * Math.PI * 2) + 4.1)));

  const cx = (size - 1) * 0.5;
  const cy = (size - 1) * 0.5;
  const stretchY = angleMode === 'pitch90' ? 0.55 : 1;
  const stretchX = shapeMode === SHAPE_VEHICLE ? 1.35 : 1;
  const radiusBase = shapeMode === SHAPE_BODY ? 0.38 : (shapeMode === SHAPE_GEAR ? 0.28 : 0.42);

  for (let y = 0; y < size; y += 1) {
    for (let x = 0; x < size; x += 1) {
      const idx = (y * size + x) * 4;
      const nx = ((x - cx) / size) / stretchX;
      const ny = ((y - cy) / size) / stretchY;
      const rr = Math.hypot(nx, ny);
      const ellipse = rr <= radiusBase;
      const trimBottom = shapeMode === SHAPE_GEAR ? (y > (size * 0.8)) : false;
      const trimTop = shapeMode === SHAPE_VEHICLE ? (y < (size * 0.36)) : false;
      const alpha = ellipse && !trimBottom && !trimTop ? 255 : 0;
      if (alpha <= 0) {
        data[idx + 0] = 0;
        data[idx + 1] = 0;
        data[idx + 2] = 0;
        data[idx + 3] = 0;
        continue;
      }
      if (normalMode) {
        const dz = Math.sqrt(Math.max(0, 1 - Math.min(1, rr / Math.max(0.001, radiusBase))));
        const nnx = clampToByte(((nx * 0.72) + 1) * 0.5 * 255);
        const nny = clampToByte(((-ny * 0.72) + 1) * 0.5 * 255);
        const nnz = clampToByte(((dz * 0.9) + 0.1) * 255);
        data[idx + 0] = nnx;
        data[idx + 1] = nny;
        data[idx + 2] = nnz;
        data[idx + 3] = 255;
      } else {
        const shade = 0.72 + (0.28 * (1 - rr / radiusBase));
        data[idx + 0] = clampToByte(baseR * shade);
        data[idx + 1] = clampToByte(baseG * shade);
        data[idx + 2] = clampToByte(baseB * shade);
        data[idx + 3] = alpha;
      }
    }
  }

  return data;
};

const clampToByte = (value) => Math.max(0, Math.min(255, Math.round(value)));

const createTextureArray = (gl, slices, size, angleMode, shapeMode, normalMode = false) => {
  const tex = gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D_ARRAY, tex);
  gl.texParameteri(gl.TEXTURE_2D_ARRAY, gl.TEXTURE_MIN_FILTER, gl.LINEAR_MIPMAP_LINEAR);
  gl.texParameteri(gl.TEXTURE_2D_ARRAY, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D_ARRAY, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D_ARRAY, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
  gl.texImage3D(
    gl.TEXTURE_2D_ARRAY,
    0,
    gl.RGBA8,
    size,
    size,
    slices,
    0,
    gl.RGBA,
    gl.UNSIGNED_BYTE,
    null
  );
  for (let i = 0; i < slices; i += 1) {
    const layer = fillTextureLayer(size, i, slices, angleMode, shapeMode, normalMode);
    gl.texSubImage3D(
      gl.TEXTURE_2D_ARRAY,
      0,
      0,
      0,
      i,
      size,
      size,
      1,
      gl.RGBA,
      gl.UNSIGNED_BYTE,
      layer
    );
  }
  gl.generateMipmap(gl.TEXTURE_2D_ARRAY);
  gl.bindTexture(gl.TEXTURE_2D_ARRAY, null);
  return tex;
};

export default class ImpostorRenderer {
  constructor(gl, options = {}) {
    this.gl = gl;
    this.maxSlices = Math.max(8, Number(options.maxSlices) || 32);
    this.textureSize = Math.max(16, Number(options.textureSize) || 64);
    this.instanceBuffer = createDynamicInstanceBuffer(gl, 4096 * UNIT_INSTANCE_STRIDE);
    this.instanceCapacity = 4096;

    this.program = createProgram(gl, VS, FS);
    this.attrs = {
      position: 0,
      uv: 1,
      iData0: 2,
      iData1: 3,
      iData2: 4,
      iData3: 5,
      iData4: 6
    };
    const quad = createStaticQuadVao(gl, this.attrs);
    this.vao = quad.vao;
    this.quadBuffer = quad.quadBuffer;

    this.uniforms = {
      uViewProj: gl.getUniformLocation(this.program, 'uViewProj'),
      uCameraRight: gl.getUniformLocation(this.program, 'uCameraRight'),
      uLayer: gl.getUniformLocation(this.program, 'uLayer'),
      uApplyYaw: gl.getUniformLocation(this.program, 'uApplyYaw'),
      uTopBlend: gl.getUniformLocation(this.program, 'uTopBlend'),
      uLightDir: gl.getUniformLocation(this.program, 'uLightDir'),
      uPitchMix: gl.getUniformLocation(this.program, 'uPitchMix'),
      uTexArray: gl.getUniformLocation(this.program, 'uTexArray'),
      uUseTexArray: gl.getUniformLocation(this.program, 'uUseTexArray'),
      uTexLayerCount: gl.getUniformLocation(this.program, 'uTexLayerCount')
    };

    this.instanceData = new Float32Array(UNIT_INSTANCE_STRIDE * this.instanceCapacity);
    this.instanceCount = 0;
    this.textureArray = null;
    this.textureLayers = 0;
    this.bindInstanceLayout();
  }

  setTextureArray(texture, layers = 0) {
    this.textureArray = texture || null;
    this.textureLayers = Math.max(0, Number(layers) || 0);
  }

  createLayerTextureSet(shapeMode) {
    const gl = this.gl;
    return {
      albedo40: createTextureArray(gl, this.maxSlices, this.textureSize, 'pitch40', shapeMode, false),
      albedo90: createTextureArray(gl, this.maxSlices, this.textureSize, 'pitch90', shapeMode, false),
      normal40: createTextureArray(gl, this.maxSlices, this.textureSize, 'pitch40', shapeMode, true),
      normal90: createTextureArray(gl, this.maxSlices, this.textureSize, 'pitch90', shapeMode, true)
    };
  }

  ensureCapacity(count) {
    if (count <= this.instanceCapacity) return;
    const gl = this.gl;
    this.instanceCapacity = Math.max(count, Math.floor(this.instanceCapacity * 1.5));
    this.instanceData = new Float32Array(this.instanceCapacity * UNIT_INSTANCE_STRIDE);
    gl.deleteBuffer(this.instanceBuffer);
    this.instanceBuffer = createDynamicInstanceBuffer(gl, this.instanceCapacity * UNIT_INSTANCE_STRIDE);
    this.bindInstanceLayout();
  }

  bindInstanceLayout() {
    const gl = this.gl;
    gl.bindVertexArray(this.vao);
    gl.bindBuffer(gl.ARRAY_BUFFER, this.instanceBuffer);
    const strideBytes = UNIT_INSTANCE_STRIDE * 4;

    gl.enableVertexAttribArray(this.attrs.iData0);
    gl.vertexAttribPointer(this.attrs.iData0, 4, gl.FLOAT, false, strideBytes, 0);
    gl.vertexAttribDivisor(this.attrs.iData0, 1);

    gl.enableVertexAttribArray(this.attrs.iData1);
    gl.vertexAttribPointer(this.attrs.iData1, 4, gl.FLOAT, false, strideBytes, 16);
    gl.vertexAttribDivisor(this.attrs.iData1, 1);

    gl.enableVertexAttribArray(this.attrs.iData2);
    gl.vertexAttribPointer(this.attrs.iData2, 4, gl.FLOAT, false, strideBytes, 32);
    gl.vertexAttribDivisor(this.attrs.iData2, 1);

    gl.enableVertexAttribArray(this.attrs.iData3);
    gl.vertexAttribPointer(this.attrs.iData3, 4, gl.FLOAT, false, strideBytes, 48);
    gl.vertexAttribDivisor(this.attrs.iData3, 1);

    gl.enableVertexAttribArray(this.attrs.iData4);
    gl.vertexAttribPointer(this.attrs.iData4, 4, gl.FLOAT, false, strideBytes, 64);
    gl.vertexAttribDivisor(this.attrs.iData4, 1);

    gl.bindVertexArray(null);
    gl.bindBuffer(gl.ARRAY_BUFFER, null);
  }

  updateFromSnapshot(snapshotUnits) {
    const count = Math.max(0, Number(snapshotUnits?.count) || 0);
    this.ensureCapacity(count);
    if (count <= 0) {
      this.instanceCount = 0;
      return;
    }
    const source = snapshotUnits?.data;
    if (!(source instanceof Float32Array)) {
      this.instanceCount = 0;
      return;
    }
    const needed = count * UNIT_INSTANCE_STRIDE;
    this.instanceData.set(source.subarray(0, needed), 0);
    this.instanceCount = count;
    updateDynamicBuffer(this.gl, this.instanceBuffer, this.instanceData, needed);
  }

  render(cameraState, pitchMix = 0, options = {}) {
    if (this.instanceCount <= 0) return;
    const gl = this.gl;
    const applyYaw = options?.applyYaw === true;

    const safePitchMix = Math.max(0, Math.min(1, Number(pitchMix) || 0));
    const topBlend = clamp01((safePitchMix - 0.55) / Math.max(1e-6, (0.75 - 0.55)));
    const smoothTopBlend = topBlend * topBlend * (3 - (2 * topBlend));

    gl.useProgram(this.program);
    gl.bindVertexArray(this.vao);
    gl.uniformMatrix4fv(this.uniforms.uViewProj, false, new Float32Array(cameraState.viewProjection));
    gl.uniform3fv(this.uniforms.uCameraRight, new Float32Array(cameraState.cameraRight));
    gl.uniform1f(this.uniforms.uApplyYaw, applyYaw ? 1 : 0);
    gl.uniform1f(this.uniforms.uTopBlend, smoothTopBlend);
    gl.uniform3f(this.uniforms.uLightDir, -0.24, -0.35, 0.91);
    gl.uniform1f(this.uniforms.uPitchMix, safePitchMix);
    if (this.textureArray) {
      gl.activeTexture(gl.TEXTURE0);
      gl.bindTexture(gl.TEXTURE_2D_ARRAY, this.textureArray);
      gl.uniform1i(this.uniforms.uTexArray, 0);
      gl.uniform1f(this.uniforms.uUseTexArray, 1);
      gl.uniform1f(this.uniforms.uTexLayerCount, Math.max(1, Number(this.textureLayers) || Number(this.maxSlices) || 1));
    } else {
      gl.uniform1f(this.uniforms.uUseTexArray, 0);
      gl.uniform1f(this.uniforms.uTexLayerCount, Math.max(1, Number(this.maxSlices) || 1));
    }

    for (let layer = 0; layer < 4; layer += 1) {
      gl.uniform1f(this.uniforms.uLayer, layer);
      gl.drawArraysInstanced(gl.TRIANGLE_STRIP, 0, 4, this.instanceCount);
    }

    gl.bindVertexArray(null);
    gl.bindTexture(gl.TEXTURE_2D_ARRAY, null);
    gl.useProgram(null);
  }

  dispose() {
    const gl = this.gl;
    if (!gl) return;
    if (this.program) gl.deleteProgram(this.program);
    if (this.instanceBuffer) gl.deleteBuffer(this.instanceBuffer);
    if (this.quadBuffer) gl.deleteBuffer(this.quadBuffer);
    if (this.vao) gl.deleteVertexArray(this.vao);
  }
}
